insert into public.blocks (id, section_id, chapter_id, title, sort_order, page_count_label, summary, explanatory_payload, existing_source, research_gaps, current_support_level, status, notes) values
  ('B1', 'introduction', 'intro', 'Ellen and John Clarke buy poisoned hokey-pokey, June 8, 1885', 1, '4', 'Reframe the opening around why ice cream matters as a historical subject: people once wanted it badly enough to risk illness or death, while modern readers take it for granted. Ellen and John Clarke''s poisoned hokey-pokey should establish that ice cream is not trivial here; it is a way to study how pleasures become ordinary through labor, technology, regulation, class conflict, and public health reform', 'Reframe the opening around why ice cream matters as a historical subject: people once wanted it badly enough to risk illness or death, while modern readers take it for granted. Ellen and John Clarke''s poisoned hokey-pokey should establish that ice cream is not trivial here; it is a way to study how pleasures become ordinary through labor, technology, regulation, class conflict, and public health reform. The scene should make the reader want to know what changed between then and now.', 'Introduction; Ch. 7 "Siren''s Call"', 'Scene reconstruction; cleaner hook; exact newspaper/source verification', 55, 'draftable', 'Audit: workable; ~55% present. Reframed per user note'),
  ('B2', 'introduction', 'intro', 'Dramatis personae: Tudor, Gatti, Marshall, vendors, doctors, inspectors, elite diners, working-class children', 2, '3', 'Use this as a brisk theatrical cast list, not a second introduction. Tudor explains the commodity ice system; Gatti explains migration, entrepreneurship, street pleasure, and labor; Marshall explains celebrity cookery, aspirational class culture, and future-facing food technology; doctors, inspectors, vendors, children, elite diners, and reformers populate the conflict around them', 'Use this as a brisk theatrical cast list, not a second introduction. Tudor explains the commodity ice system; Gatti explains migration, entrepreneurship, street pleasure, and labor; Marshall explains celebrity cookery, aspirational class culture, and future-facing food technology; doctors, inspectors, vendors, children, elite diners, and reformers populate the conflict around them. The point is recognition: when these people return later, the reader already knows what role they play.', 'Project plan; thesis chapters on Gatti, Marshall, disease', 'Tight character sketches; avoid over-explaining arcs', 70, 'draftable', 'Audit: workable; ~70% present. Keep brisk'),
  ('B3', 'introduction', 'intro', 'Curtain-pull: two ice creams in Victorian Britain', 3, '3', 'State the governing contrast clearly. Victorian Britain did not have one ice cream culture but two: Gatti''s public, immigrant, cheap, democratic, dangerous ice cream, and Marshall''s elite, theatrical, professionalized, aspirational ice cream', 'State the governing contrast clearly. Victorian Britain did not have one ice cream culture but two: Gatti''s public, immigrant, cheap, democratic, dangerous ice cream, and Marshall''s elite, theatrical, professionalized, aspirational ice cream. This block should give the reader the book''s map without prematurely arguing every point.', 'Introduction; Ch. 6 "Scales of Justice"', 'Concise thesis statement in trade prose', 80, 'draftable', 'Audit: workable; ~80% present. Governing frame'),
  ('B4', 'part-i-before-victoria', 'ch-01', 'Roman snow, elite cold, and the snow-is-not-ice-cream pivot', 4, '3', 'Use Roman snow and elite cold luxuries as the setup, then pivot hard: cold snow is not ice cream. The block should show ancient status and season-defiance, but its real job is to create the reader question that launches the next block: if snow-cooled wine and cold luxuries are only ancestors, who first moved toward something recognizably like ice cream? The working answer in this plan is China, pending the user research pass.', 'Use Roman snow and elite cold luxuries as the setup, then pivot hard: cold snow is not ice cream. The block should show ancient status and season-defiance, but its real job is to create the reader question that launches the next block: if snow-cooled wine and cold luxuries are only ancestors, who first moved toward something recognizably like ice cream? The working answer in this plan is China, pending the user research pass.', 'Ch. 3 "Not-so-Brief History"; initial bibliography', 'Verify Roman claims; avoid overclaiming direct lineage', 60, 'draftable', 'Audit: workable; ~60% present. Recast as pivot'),
  ('B5', 'part-i-before-victoria', 'ch-01', 'Chinese chilled/frozen preparations as the first ice-cream answer', 5, '7', 'Make this the chapter''s central answer to “who came up with ice cream?” rather than a cautious side note. The user will add research to make the claim solid, so the block should be built to distinguish evidence from legend while still giving the reader a satisfying account of Chinese chilled or frozen preparations, how they differed from mere snow, and why they belong in the lineage of ice cream.', 'Make this the chapter''s central answer to “who came up with ice cream?” rather than a cautious side note. The user will add research to make the claim solid, so the block should be built to distinguish evidence from legend while still giving the reader a satisfying account of Chinese chilled or frozen preparations, how they differed from mere snow, and why they belong in the lineage of ice cream.', 'Ch. 3; general ice cream histories', 'User research pass to make Chinese-origin claim rock solid; verify evidence and terminology. Audit adds: Substantial new research on Chinese chilled/frozen preparations, terminology, evidence chain, and historiographical caution.', 5, 'research', 'Audit: research-dependent; ~5% present. Expand with new research Keep 7 pp only if Chinese-origin research is verified; otherwise compress sharply.'),
  ('B6', 'part-i-before-victoria', 'ch-01', 'Persian sharbat and Middle Eastern cold sweets', 6, '5', 'Use Persian sharbat and Middle Eastern cold sweets as a researched secondary thread after China: syrups, fruit, perfume, snow or ice, elite refreshment, and culinary transfer. The user plans more research here, so this block should remain open enough to absorb stronger sources while keeping its narrative function clear: it broadens the origin story from invention to transmission, flavor, and refinement.', 'Use Persian sharbat and Middle Eastern cold sweets as a researched secondary thread after China: syrups, fruit, perfume, snow or ice, elite refreshment, and culinary transfer. The user plans more research here, so this block should remain open enough to absorb stronger sources while keeping its narrative function clear: it broadens the origin story from invention to transmission, flavor, and refinement.', 'Ch. 3; bibliography', 'Additional Persian / Middle Eastern culinary research; clarify transfer path into European confectionery. Audit adds: Research Persian sharbat, Middle Eastern cold sweets, transfer routes, ingredients, and terminology; distinguish snow-cooled drinks from ice cream lineage.', 25, 'research', 'Audit: research-dependent; ~25% present. Expand with new research Keep 5 pp only if Persian/Middle Eastern research is added; otherwise use as Audiger/sherbet bridge.'),
  ('B7', 'part-i-before-victoria', 'ch-02', 'Italy before Florence: arrival, reception, service, and making', 7, '5', 'This block now covers everything up to the Florentine snow holes. It should answer the user''s practical reader questions: where did ice cream or its close ancestors first land in Italy, how was it received, how was it served, how was it made, and whether “Neapolitan” has a historically meaningful place in the story', 'This block now covers everything up to the Florentine snow holes. It should answer the user''s practical reader questions: where did ice cream or its close ancestors first land in Italy, how was it received, how was it served, how was it made, and whether “Neapolitan” has a historically meaningful place in the story. Use Naples, snow economies, Vesuvius, ice pits, service culture, and early Italian reception before handing off to Florence.', 'Ch. 3; historiography', 'Research Neapolitan angle; concrete sources for Italian arrival, service, and making before Florence', 70, 'draftable', 'Audit: workable; ~70% present. Recast and set to 5 pp'),
  ('B8', 'part-i-before-victoria', 'ch-02', 'Florentine snow holes and Buontalenti', 8, '7', 'Begin with the Florentine snow holes and build a full Buontalenti story. The emphasis should be infrastructure, spectacle, and courtly engineering rather than a simplistic “inventor of gelato” claim', 'Begin with the Florentine snow holes and build a full Buontalenti story. The emphasis should be infrastructure, spectacle, and courtly engineering rather than a simplistic “inventor of gelato” claim. Use Montaigne in Florence, Pratolino, Medici residences, ice houses, snow-hole control, and Buontalenti''s theatrical skill to show how Florence made cold into architecture, performance, and legend.', 'Ch. 3, if present', 'Verify and caveat; decide how much legend to keep', 75, 'draftable', 'Audit: workable; ~75% present. Expanded to 7 pp'),
  ('B9', 'part-i-before-victoria', 'ch-02', 'Migration to France; French court/cafe/salon culture', 9, '8', 'Use France to explain how frozen sweets became culinary prestige. Audiger is the key protagonist: trained across Europe, fluent in sherbets and court service, serving water ices to the Dauphin and Louis XIV, and recording an early iced cream recipe', 'Use France to explain how frozen sweets became culinary prestige. Audiger is the key protagonist: trained across Europe, fluent in sherbets and court service, serving water ices to the Dauphin and Louis XIV, and recording an early iced cream recipe. Massialot then adds custard and print transmission. The block should make French culinary authority concrete through officier service, court performance, cafes/salons, and recipe publication.', 'Ch. 3; historiography on French culinary authority', 'Better scenes; clarify role of confectioners versus courts', 80, 'draftable', 'Audit: workable; ~80% present. Keep'),
  ('B10', 'part-i-before-victoria', 'ch-03', 'America, Frederic Tudor, speculative voyages, and the Ice King', 10, '5', 'Use Tudor as both the introduction to America and the main ice-trade protagonist. This is the first substantial American reference, so explain why American climate and abundant natural ice made a different ice-cream culture possible', 'Use Tudor as both the introduction to America and the main ice-trade protagonist. This is the first substantial American reference, so explain why American climate and abundant natural ice made a different ice-cream culture possible. Then tell Tudor''s whole arc in one block: speculative voyages, ridicule, losses, debtor''s prison, persistence, Calcutta triumph, and the making of the Ice King. B12 is folded here so Tudor reads as one clean narrative unit.', 'Ch. 3; old Ch. 1 notes', 'Scene expansion; confirmed chronology; America-as-ice-culture setup', 85, 'draftable', 'Audit: strong existing base; ~85% present. Expanded / absorbs B12'),
  ('B11', 'part-i-before-victoria', 'ch-03', 'Ice cutting, sawdust packing, ocean shipping', 11, '5', 'This remains the practical “how did people get ice before refrigerators?” block, but it should now include Hudson River ice houses and a wider look at how other parts of Europe got ice. Explain harvesting, ice houses, sawdust, ships, melt loss, labor, storage, and regional alternatives', 'This remains the practical “how did people get ice before refrigerators?” block, but it should now include Hudson River ice houses and a wider look at how other parts of Europe got ice. Explain harvesting, ice houses, sawdust, ships, melt loss, labor, storage, and regional alternatives. The payoff should be a clear answer to natural ice logistics before the story turns to British fashion and Gatti''s business use of the system.', 'Ch. 3; secondary sources', 'Hudson ice houses; research how other parts of Europe sourced/stored ice', 65, 'draftable', 'Audit: workable; ~65% present. Expanded logistics block'),
  ('B12', 'part-i-before-victoria', 'ch-04', 'Regency London: early recipes, pleasure gardens, and first sensory encounters', 12, '5', 'Start British popularization before the Wenham window. The point is not simply that the upper class consumed ice, but how ice cream reached London and became meaningful there: first English cookbook appearances, pleasure gardens, early recipes, confectioners, sensory surprise, and upper-class public consumption', 'Start British popularization before the Wenham window. The point is not simply that the upper class consumed ice, but how ice cream reached London and became meaningful there: first English cookbook appearances, pleasure gardens, early recipes, confectioners, sensory surprise, and upper-class public consumption. This block should be at least five pages and make the pre-Victorian London story feel alive before imported ice infrastructure becomes the focus.', 'Ch. 3; Hannah Glasse; Chesterfield; Negri/Nutt/Gunter material', 'More Regency sensory scenes; verify early English cookbook and pleasure-garden sequence', 85, 'draftable', 'Audit: strong existing base; ~85% present. Expanded per user note'),
  ('B13', 'part-i-before-victoria', 'ch-04', 'Wenham window, aristocratic endorsement, and public ice spectacle', 13, '4', 'Then move into the ice in the window. Combine the old Wenham, royal/aristocratic endorsement, Punch satire, Peel/tariff, and public-spectacle material into one block about imported ice becoming visible, fashionable, and funny', 'Then move into the ice in the window. Combine the old Wenham, royal/aristocratic endorsement, Punch satire, Peel/tariff, and public-spectacle material into one block about imported ice becoming visible, fashionable, and funny. The argument is that British consumers learned to see ice itself as refinement before mass-market ice cream became possible.', 'Ch. 3; Wenham Lake; Queen Victoria / Albert; Punch; Peel', 'Verify royal details; select best window/satire material', 85, 'draftable', 'Audit: strong existing base; ~85% present. Combines old B14-B15 material'),
  ('B14', 'part-i-before-victoria', 'ch-04', 'Norwegian ice as teaser for Gatti''s opportunity', 14, '3', 'Use this as a short teaser rather than a full infrastructure block. Norway, Lake Oppegaard rebranding, low-margin Anglo-Norwegian ice, and practical shipping advantages should point forward to Gatti: elite demand built the system, but immigrant entrepreneurs could repurpose that system for mass pleasure.', 'Use this as a short teaser rather than a full infrastructure block. Norway, Lake Oppegaard rebranding, low-margin Anglo-Norwegian ice, and practical shipping advantages should point forward to Gatti: elite demand built the system, but immigrant entrepreneurs could repurpose that system for mass pleasure.', 'Ch. 3; Introduction', 'Bridge to Gatti''s mass-market opportunity', 75, 'draftable', 'Audit: workable; ~75% present. Short teaser'),
  ('B15', 'part-ii-carlo-gatti', 'ch-05', 'A street tour of Saffron Hill before Gatti', 15, '5', 'Keep Gatti offstage. This block should be a lived street tour of the slums: what the reader sees, smells, hears, and notices; where people stand or work; what crowding feels like; how policing, poverty, dirt, trade, and proximity shape daily life', 'Keep Gatti offstage. This block should be a lived street tour of the slums: what the reader sees, smells, hears, and notices; where people stand or work; what crowding feels like; how policing, poverty, dirt, trade, and proximity shape daily life. Use Dickens and the Hatton Garden contrast, but focus less on biography and more on the physical and sensory conditions of the neighborhood.', 'Ch. 4 "Oh How Little!"', 'Broader urban context; sensory reconstruction', 70, 'draftable', 'Audit: workable; ~70% present. Good; no Gatti yet'),
  ('B16', 'part-ii-carlo-gatti', 'ch-05', 'Economic distinctions inside the slums', 16, '5', 'Focus on the economic distinctions among people and places in the slums. Take each person, trade, lodging, shop, street, or institution described in the source material and slot it into a practical class structure: who is barely surviving, who is skilled, who is mobile, who exploits whom, who has a route out', 'Focus on the economic distinctions among people and places in the slums. Take each person, trade, lodging, shop, street, or institution described in the source material and slot it into a practical class structure: who is barely surviving, who is skilled, who is mobile, who exploits whom, who has a route out. This should make Saffron Hill socially legible before Gatti enters in a later chapter.', 'Ch. 4', 'Class-map the people/places from existing Saffron Hill material', 65, 'draftable', 'Audit: workable; ~65% present. Recast per user note'),
  ('B17', 'part-ii-carlo-gatti', 'ch-06', 'Ticino and Valle di Blenio before Gatti', 17, '3', 'Do not introduce Gatti yet. Use this block as a regional introduction to Ticino and the Valle di Blenio: terrain, poverty, mobility, seasonal work, language, Swiss/Italian identity, and outward migration', 'Do not introduce Gatti yet. Use this block as a regional introduction to Ticino and the Valle di Blenio: terrain, poverty, mobility, seasonal work, language, Swiss/Italian identity, and outward migration. The chapter should make the region understandable on its own terms before Gatti becomes one example of a larger pattern.', 'Ch. 4', 'Ticino migration research. Audit adds: Research Ticino, Valle di Blenio, terrain, poverty, seasonal work, language, Swiss/Italian identity, and migration.', 25, 'research', 'Audit: research-dependent; ~25% present. Good; no Gatti yet'),
  ('B18', 'part-ii-carlo-gatti', 'ch-06', 'Risorgimento as political weather', 18, '4', 'Give the promised “what was going on in Italy?” answer in usable form. The Risorgimento should be political weather around migration, not a textbook detour: unification, regional prejudice, Capture of Rome, Franco-Prussian disruption, and the formation of Italian identity all affect how migrants are seen and how they organize abroad', 'Give the promised “what was going on in Italy?” answer in usable form. The Risorgimento should be political weather around migration, not a textbook detour: unification, regional prejudice, Capture of Rome, Franco-Prussian disruption, and the formation of Italian identity all affect how migrants are seen and how they organize abroad. Tie every paragraph back to labor movement, diaspora, and the ice trade.', 'Ch. 4 only lightly', 'New Risorgimento/displacement synthesis tied to migration. Audit adds: Draft a concise Risorgimento/displacement synthesis tied to labor movement and diaspora; avoid textbook detour.', 40, 'research', 'Audit: research-dependent; ~40% present. Good'),
  ('B19', 'part-ii-carlo-gatti', 'ch-06', 'Italian-speaking migrant routes through Paris and London', 19, '3', 'Show the routes and networks that made later hokey-pokey possible. Paris matters as a staging point for skill, contacts, marriage, and reinvention; London matters as a market; Ticinese and Italian networks later supply workers', 'Show the routes and networks that made later hokey-pokey possible. Paris matters as a staging point for skill, contacts, marriage, and reinvention; London matters as a market; Ticinese and Italian networks later supply workers. This block should lay groundwork for the padroni/patron labor system without making claims beyond the evidence.', 'Ch. 4', 'Migration-network sources; Paris gap. Audit adds: Research migration routes through Paris and London, kin/work networks, contacts, marriage, and skill transfer.', 35, 'research', 'Audit: research-dependent; ~35% present. Good'),
  ('B20', 'part-ii-carlo-gatti', 'ch-07', 'School caning; 600-mile walk to Paris', 20, '5', 'Turn Gatti''s school caning and walk to Paris into a physical migration scene. The walk is memorable because it makes ambition bodily: distance, fatigue, language, weather, roads, and the psychological break from home', 'Turn Gatti''s school caning and walk to Paris into a physical migration scene. The walk is memorable because it makes ambition bodily: distance, fatigue, language, weather, roads, and the psychological break from home. Verify the anecdote, but if it holds, it gives the reader Gatti before he becomes a businessman.', 'Ch. 4', 'Route reconstruction; verify anecdote details. Audit adds: Verify anecdote; reconstruct route, weather, roads, language, fatigue, and emotional break from home.', 35, 'research', 'Audit: research-dependent; ~35% present. Good Five pages require route reconstruction; shrink if anecdote cannot be verified.'),
  ('B21', 'part-ii-carlo-gatti', 'ch-07', 'Paris years, marriage, Dover arrival, July 2, 1847', 21, '5', 'Fill the Paris-to-Dover gap as much as evidence permits. This block covers marriage in 1839, possible skill acquisition, contacts, family separation, and arrival at Dover on July 2, 1847', 'Fill the Paris-to-Dover gap as much as evidence permits. This block covers marriage in 1839, possible skill acquisition, contacts, family separation, and arrival at Dover on July 2, 1847. Its narrative purpose is transition: Gatti stops being a runaway boy and becomes a migrant husband entering London''s opportunity structure.', 'Ch. 4', 'User will look for more Paris-years material; clarify timeline if evidence permits. Audit adds: Find Paris-years evidence if possible; clarify skill acquisition, contacts, family separation, and Dover documentation.', 30, 'research', 'Audit: research-dependent; ~30% present. Open research gap Five pages require Paris-years evidence; avoid filling with speculation.'),
  ('B22', 'part-ii-carlo-gatti', 'ch-07', 'Saffron Hill, children''s deaths, first coffee-house partnership, move out by 1851', 22, '5', 'Use Saffron Hill, family deaths, the coffee cart or cafe partnership, and the 1851 move out of the slums to make Gatti emotionally legible. This is where vulnerability and calculation should coexist: he suffers losses, works inside a migrant enclave, uses kin/work networks, and begins climbing faster than most around him.', 'Use Saffron Hill, family deaths, the coffee cart or cafe partnership, and the 1851 move out of the slums to make Gatti emotionally legible. This is where vulnerability and calculation should coexist: he suffers losses, works inside a migrant enclave, uses kin/work networks, and begins climbing faster than most around him.', 'Ch. 4', 'Emotional texture; family records if available', 65, 'draftable', 'Audit: workable; ~65% present. Good'),
  ('B23', 'part-ii-carlo-gatti', 'ch-08', 'Hungerford Market and Great Exhibition chocolate machine', 23, '3', 'Make Hungerford Market feel lived before it becomes a business turning point. Reconstruct the intended grandeur versus shabby reality, the crowds, sounds, food, music, shopfronts, entertainment, “not very picked company,” and Gatti''s use of spectacle such as the Great Exhibition chocolate machine', 'Make Hungerford Market feel lived before it becomes a business turning point. Reconstruct the intended grandeur versus shabby reality, the crowds, sounds, food, music, shopfronts, entertainment, “not very picked company,” and Gatti''s use of spectacle such as the Great Exhibition chocolate machine. The reader should understand the market as an atmosphere and opportunity, not just a location in Gatti''s career.', 'Ch. 4', 'Fuller lived-market reconstruction; exhibition and crowd texture', 75, 'draftable', 'Audit: workable; ~75% present. Expand atmosphere'),
  ('B24', 'part-ii-carlo-gatti', 'ch-08', 'Hungerford Hall fire and Wellington funeral canvas', 24, '3', 'Make the Hungerford Hall fire a turning-point scene. The thesis has March 31, 1854, the Wellington funeral canvas, damaged insured stalls, and the shabby market setting', 'Make the Hungerford Hall fire a turning-point scene. The thesis has March 31, 1854, the Wellington funeral canvas, damaged insured stalls, and the shabby market setting. The block should stage disaster vividly while preserving ambiguity: the fire matters whether or not suspicion can be proved.', 'Ch. 4', 'Fuller fire scene', 75, 'draftable', 'Audit: workable; ~75% present. Good'),
  ('B25', 'part-ii-carlo-gatti', 'ch-08', 'Insurance payout, fraud question, rebuilding, real estate opportunity', 25, '4', 'Explain how insurance, rebuilding, railway demolition, and real-estate timing turn damage into capital. Keep the fraud question cautious: suspicion, rumor, or interpretive ambiguity, not accusation', 'Explain how insurance, rebuilding, railway demolition, and real-estate timing turn damage into capital. Keep the fraud question cautious: suspicion, rumor, or interpretive ambiguity, not accusation. The main point is that Gatti emerges with money, market position, and the ability to invest in ice infrastructure and labor.', 'Ch. 4', 'Cautious handling of suspicion; more business context', 80, 'draftable', 'Audit: workable; ~80% present. Good'),
  ('B26', 'part-ii-carlo-gatti', 'ch-09', 'Who sold hokey-pokey?', 26, '3', 'Start the chapter with the people selling ice cream, not with enjoyment. Introduce the vendors: Italian and Ticinese laborers, later southern Italians, boys and young men, patron networks, street cries, carts, routes, housing, language, and public visibility', 'Start the chapter with the people selling ice cream, not with enjoyment. Introduce the vendors: Italian and Ticinese laborers, later southern Italians, boys and young men, patron networks, street cries, carts, routes, housing, language, and public visibility. This block should answer “who were they?” before the chapter follows their working day and then turns to customers.', 'Ch. 4; Ch. 7; Mayhew; Smith; London Italian Gazette', 'Clarify vendor origins and distinguish Gatti evidence from broader trade', 75, 'draftable', 'Audit: workable; ~75% present. Swapped with old B31 job'),
  ('B27', 'part-ii-carlo-gatti', 'ch-09', 'Thomson & Smith: 4 AM depot, evening return, games of mora', 27, '3', 'Build the vendor day from Thomson & Smith and related street-life sources: 4 AM depot, carts, rounds, returning in the evening, games of mora, language, lodging, and fatigue. This is the human routine behind the commodity', 'Build the vendor day from Thomson & Smith and related street-life sources: 4 AM depot, carts, rounds, returning in the evening, games of mora, language, lodging, and fatigue. This is the human routine behind the commodity. It should also show why vendors were visible enough to become a “distinct feature of London life.”', 'Ch. 7 "Siren''s Call"', 'Fuller scene treatment', 60, 'draftable', 'Audit: workable; ~60% present. Keep here'),
  ('B28', 'part-ii-carlo-gatti', 'ch-09', 'How hokey-pokey was enjoyed', 28, '4', 'End the chapter with the experience of eating hokey-pokey: “ecco un poco,” penny and halfpenny sales, first-taste scenes, tooth shock, children, servant-maid knowledge, working-class pleasure, and the small bodily comedy of learning how to eat ice. This now carries the old democratization/enjoyment material after the reader has met the sellers and watched their day.', 'End the chapter with the experience of eating hokey-pokey: “ecco un poco,” penny and halfpenny sales, first-taste scenes, tooth shock, children, servant-maid knowledge, working-class pleasure, and the small bodily comedy of learning how to eat ice. This now carries the old democratization/enjoyment material after the reader has met the sellers and watched their day.', 'Ch. 4; Ch. 7; Mayhew first-taste scenes; Daily Telegraph pleasure source', 'Etymology verification; street-sale economics; pleasure scenes', 90, 'draftable', 'Audit: strong existing base; ~90% present. Swapped with old B29 job'),
  ('B29', 'part-ii-carlo-gatti', 'ch-10', 'Penny lick glass mechanics', 29, '3', 'Explain the penny lick glass mechanically and viscerally. A single glass moves from mouth to mouth; vendors often rinse poorly or not at all; dairy and sugar hold contamination; children are the most enthusiastic customers', 'Explain the penny lick glass mechanically and viscerally. A single glass moves from mouth to mouth; vendors often rinse poorly or not at all; dairy and sugar hold contamination; children are the most enthusiastic customers. This block should make the reader understand disease transmission without needing abstract medical exposition.', 'Ch. 7; Ch. 6', 'Tight technical explanation', 90, 'draftable', 'Audit: strong existing base; ~90% present. Strong'),
  ('B30', 'part-ii-carlo-gatti', 'ch-10', 'Milk scares, germ theory, Victorian medicine', 30, '3', 'Give germ theory and milk scares just enough room to change the reader''s frame. Koch, miasma, microbes, sealed tins, scalding, and milk purity anxieties all help explain why Victorians began to see street ice not merely as dirty-looking but as biologically dangerous', 'Give germ theory and milk scares just enough room to change the reader''s frame. Koch, miasma, microbes, sealed tins, scalding, and milk purity anxieties all help explain why Victorians began to see street ice not merely as dirty-looking but as biologically dangerous. Keep this subordinate to scene, not a separate history of medicine.', 'Ch. 7; Ch. 6', 'Koch/miasma/public-understanding context', 75, 'draftable', 'Audit: workable; ~75% present. Needs synthesis'),
  ('B31', 'part-ii-carlo-gatti', 'ch-10', '*Pall Mall Gazette*, Eyre Street Hill, Bate report, contamination list', 31, '4', 'Consolidate the strongest contamination evidence into one investigative sequence: Pall Mall Gazette, Eyre Street Hill, backyards and dwellings, Dr. Bate''s 1895 report, fecal or diarrheal contamination, skin cells, mucus, dust, hair, sewage, textile fibers, lice, fleas, bedbugs, and vermin', 'Consolidate the strongest contamination evidence into one investigative sequence: Pall Mall Gazette, Eyre Street Hill, backyards and dwellings, Dr. Bate''s 1895 report, fecal or diarrheal contamination, skin cells, mucus, dust, hair, sewage, textile fibers, lice, fleas, bedbugs, and vermin. This is one of the book''s strongest horror chapters and should be built for accumulation.', 'Ch. 4; Ch. 7', 'Consolidate scattered evidence into one narrative', 95, 'draftable', 'Audit: strong existing base; ~95% present. Very strong'),
  ('B32', 'part-iii-agnes-marshall', 'ch-11', 'Calico ball / Jack-the-Giant-Killer with rose ice', 32, '3', 'Use the calico ball and Jack-the-Giant-Killer with rose ice cream as the cleanest counter-image to street hokey-pokey. This is not merely rich people eating better dessert; it is ice cream as performance, costume, labor, abundance, and class confidence', 'Use the calico ball and Jack-the-Giant-Killer with rose ice cream as the cleanest counter-image to street hokey-pokey. This is not merely rich people eating better dessert; it is ice cream as performance, costume, labor, abundance, and class confidence. The block should open Part III by making “the other ice cream” instantly visible.', 'Introduction', 'Fuller society scene', 60, 'draftable', 'Audit: workable; ~60% present. Good contrast'),
  ('B33', 'part-iii-agnes-marshall', 'ch-11', 'The shocking expense and strangeness of elite ice cream', 33, '3', 'Focus on shocking the modern reader: elite Victorian ice cream was expensive, materially different, strangely flavored, technically demanding, and socially coded. Use cost, ingredients, flavors, utensils, molds, menus, service, and etiquette to show that fancy ice was not simply better ice cream; it belonged to a different world from the penny lick.', 'Focus on shocking the modern reader: elite Victorian ice cream was expensive, materially different, strangely flavored, technically demanding, and socially coded. Use cost, ingredients, flavors, utensils, molds, menus, service, and etiquette to show that fancy ice was not simply better ice cream; it belonged to a different world from the penny lick.', 'Ch. 6; Introduction', 'Concrete cost comparisons; strongest odd flavors and service details', 85, 'draftable', 'Audit: strong existing base; ~85% present. Recast per user note'),
  ('B34', 'part-iii-agnes-marshall', 'ch-11', 'Dining rooms, servants, menus, and display', 34, '4', 'Teach Victorian class through objects and behavior rather than theory. Use dining rooms, servants, menus, utensils, etiquette, who prepares, who serves, who pays, who licks, who spoons', 'Teach Victorian class through objects and behavior rather than theory. Use dining rooms, servants, menus, utensils, etiquette, who prepares, who serves, who pays, who licks, who spoons. John Bull licking ice cream while women eat properly can carry a great deal of class/sex/manners analysis without academic scaffolding.', 'Historiography; Ch. 6', 'Narrative class primer', 85, 'draftable', 'Audit: strong existing base; ~85% present. Avoid abstraction'),
  ('B35', 'part-iii-agnes-marshall', 'ch-12', 'Willis''s Rooms demonstration, October 1887; 600 people; bottle-green dress', 35, '4', 'Introduce Marshall at peak power before revealing hidden biography. Willis''s Rooms in October 1887 gives celebrity, theater, audience, costume, gender authority, and culinary confidence in one room', 'Introduce Marshall at peak power before revealing hidden biography. Willis''s Rooms in October 1887 gives celebrity, theater, audience, costume, gender authority, and culinary confidence in one room. The bottle-green dress, 600-person audience, 3 PM start, speech, and performance menu should make her feel like a public figure, not a recipe writer.', 'Ch. 5 "Around The Table"', 'Audience reactions; physical staging', 90, 'draftable', 'Audit: strong existing base; ~90% present. Strong opener'),
  ('B36', 'part-iii-agnes-marshall', 'ch-12', 'Two-hour performance and full menu', 36, '3', 'Use the two-hour demonstration and full menu to show cookery as theater. Lobster mayonnaise through souffles, jellies, nougat, cream, strawberry, and ice creams should demonstrate pacing, virtuosity, and spectacle', 'Use the two-hour demonstration and full menu to show cookery as theater. Lobster mayonnaise through souffles, jellies, nougat, cream, strawberry, and ice creams should demonstrate pacing, virtuosity, and spectacle. This block is also a chance to explain why demonstrations created authority: seeing Marshall perform made her products, classes, and books more credible.', 'Ch. 5', 'More detail on technique and pacing', 80, 'draftable', 'Audit: workable; ~80% present. Sensory opportunity'),
  ('B37', 'part-iii-agnes-marshall', 'ch-12', 'Mortimer Street, classes, products, *The Table*', 37, '3', 'Map the Marshall business ecosystem: Mortimer Street school, no students on first day, classes, store/warehouse across the street, Marshall''s Own Brand ingredients and equipment, The Book of Ices, The Table, advertisements, and branded freezers. The key insight is flywheel, not miscellany: each platform sells and validates the others.', 'Map the Marshall business ecosystem: Mortimer Street school, no students on first day, classes, store/warehouse across the street, Marshall''s Own Brand ingredients and equipment, The Book of Ices, The Table, advertisements, and branded freezers. The key insight is flywheel, not miscellany: each platform sells and validates the others.', 'Ch. 5', 'Stronger business-system explanation. Audit adds: Map the flywheel clearly and possibly move some business-system material into Ch. 15 to avoid crowding.', 90, 'planned', 'Audit: tight; ~90% present. Important bridge'),
  ('B38', 'part-iii-agnes-marshall', 'ch-13', 'A sensory answer to Marshall''s world', 38, '5', 'This block should answer what Marshall''s world felt and tasted like, not just what “ice cream in general” was. Use The Book of Ices, flavors, ingredients, recipes, equipment, teaching, product culture, and class aspiration to build a sensory entry into Marshall''s professional universe', 'This block should answer what Marshall''s world felt and tasted like, not just what “ice cream in general” was. Use The Book of Ices, flavors, ingredients, recipes, equipment, teaching, product culture, and class aspiration to build a sensory entry into Marshall''s professional universe. The point is to make her world available to the reader through taste, smell, texture, labor, and display.', 'Ch. 5', 'Recipe-level description', 80, 'draftable', 'Audit: workable; ~80% present. Recast per user note'),
  ('B39', 'part-iii-agnes-marshall', 'ch-13', 'Presentation and exaggerated Victorian food display', 39, '5', 'Make this less narrowly about moulds and more about presentation as the central value. Moulded fruits, flowers, architecture, tableaux, painted surfaces, edible decoration, and spectacular service should become evidence for a larger point: Victorian elite cooking often prized exaggerated presentation, abundance, and theatrical display', 'Make this less narrowly about moulds and more about presentation as the central value. Moulded fruits, flowers, architecture, tableaux, painted surfaces, edible decoration, and spectacular service should become evidence for a larger point: Victorian elite cooking often prized exaggerated presentation, abundance, and theatrical display. Ice cream mattered because cold could be staged.', 'Ch. 5; proprietary research', 'Victorian food-presentation context; visual examples beyond molds if useful', 90, 'draftable', 'Audit: strong existing base; ~90% present. Recast per user note'),
  ('B40', 'part-iii-agnes-marshall', 'ch-13', 'How Marshall created the world she lived in', 40, '5', 'Use this as the bridge between sensory world and presentation. Show how Marshall created the world she inhabited through technology, products, equipment, school instruction, branded authority, cleanliness, and aspirational access', 'Use this as the bridge between sensory world and presentation. Show how Marshall created the world she inhabited through technology, products, equipment, school instruction, branded authority, cleanliness, and aspirational access. Introduce edible cones here as part of her future-facing imagination and as a bridge toward modern ice cream, while still keeping the block grounded in her Victorian business system.', 'Ch. 6; Ch. 5', 'Clarify freezer/equipment economics; verify edible cone material; connect to business ecosystem. Audit adds: Verify edible cone precursor; connect equipment economics to brand/ecosystem; avoid overlap with B37 and B45.', 65, 'planned', 'Audit: tight; ~65% present. Bridge block / introduce cones'),
  ('B41', 'part-iii-agnes-marshall', 'ch-14', 'Public biography: middle-class origin, continental training, respectable marriage', 41, '5', 'Set up Marshall''s constructed public biography as part of her business authority. Middle-class origin, continental training, respectable marriage, school acquisition, Princess Helena dedication, portrait, charity, and The Towers all help build a credible “Mrs', 'Set up Marshall''s constructed public biography as part of her business authority. Middle-class origin, continental training, respectable marriage, school acquisition, Princess Helena dedication, portrait, charity, and The Towers all help build a credible “Mrs. Marshall.” The block should ask where the public story came from and why people needed it to be true.', 'Ch. 5; old notes', 'Verify public claims and where they appeared', 60, 'draftable', 'Audit: workable; ~60% present. Needs verification'),
  ('B42', 'part-iii-agnes-marshall', 'ch-14', 'Hidden biography, first day, and the making of Mrs. A. B. Marshall', 42, '8', 'Blend the hidden-biography material with the old first-day/reinvention block. Working-class origins, servant years, Ethel, Alfred''s imprisonment, capital mystery, first day at Mortimer Street with no pupils, and the act of becoming “Mrs', 'Blend the hidden-biography material with the old first-day/reinvention block. Working-class origins, servant years, Ethel, Alfred''s imprisonment, capital mystery, first day at Mortimer Street with no pupils, and the act of becoming “Mrs. A. B. Marshall” should read as one integrated story of concealment, risk, and self-making. The point is not scandal but the cost and necessity of respectability.', 'Old reframing notes; Jenkins material', 'Full Jenkins/source verification; careful language; Mortimer Street scene; capital mystery. Audit adds: Full Jenkins/source verification; careful language around illegitimacy, servant years, Alfred, capital, and motive; build Mortimer Street first-day scene.', 20, 'research', 'Audit: research-dependent; ~20% present. Blends old B45-B46 Eight pages depend on verified Jenkins/hidden-biography evidence.'),
  ('B43', 'part-iii-agnes-marshall', 'ch-14', 'Coda: why reinvention mattered so much', 43, '3', 'Use this new coda to answer why it mattered so intensely that Marshall invented and protected this public identity. Tie her concealments to Victorian gender, class mobility, credibility, culinary authority, entrepreneurship, marriage, and the market for respectable expertise', 'Use this new coda to answer why it mattered so intensely that Marshall invented and protected this public identity. Tie her concealments to Victorian gender, class mobility, credibility, culinary authority, entrepreneurship, marriage, and the market for respectable expertise. This block should give emotional and social meaning to the truth/lies chapter before the book turns to The Table.', 'Ch. 5; old notes; Jenkins material once verified', 'Interpretive synthesis after B45; source-sensitive claims about motive and social pressure. Audit adds: Interpretive synthesis after hidden-biography verification; tie to gender, class mobility, expertise, and respectability.', 35, 'research', 'Audit: research-dependent; ~35% present. New coda per user note'),
  ('B44', 'part-iii-agnes-marshall', 'ch-15', '*The Table* as weekly institution', 44, '3', 'Present The Table as a weekly institution and voice machine. Its gastronomy editorial, chatty authority, recipes, amusements, household advice, food science, banana enthusiasm, and long life make Marshall more than a cookbook author', 'Present The Table as a weekly institution and voice machine. Its gastronomy editorial, chatty authority, recipes, amusements, household advice, food science, banana enthusiasm, and long life make Marshall more than a cookbook author. This block should capture the pleasure of her voice and the regular relationship with readers.', 'Ch. 5; references', 'Select representative quotations', 85, 'draftable', 'Audit: strong existing base; ~85% present. Important'),
  ('B45', 'part-iii-agnes-marshall', 'ch-15', 'Recipes, advice, competitions, products, registry', 45, '4', 'Show The Table as infrastructure: recipes, product ads, school ads, freezer ads, competitions, reader advice, classifieds, employment registry, and certification. The magazine connects cooks, employers, consumers, ingredients, tools, and taste', 'Show The Table as infrastructure: recipes, product ads, school ads, freezer ads, competitions, reader advice, classifieds, employment registry, and certification. The magazine connects cooks, employers, consumers, ingredients, tools, and taste. The important annotation question is how to visualize the flywheel clearly enough for trade readers.', 'Ch. 5; proprietary research', 'Map business functions clearly', 90, 'draftable', 'Audit: strong existing base; ~90% present. Business-system block'),
  ('B46', 'part-iii-agnes-marshall', 'ch-15', 'Servant problem, worker advocacy, women''s work, technology predictions', 46, '3', 'Use servant problem, worker advocacy, women''s work, manners instruction, and technology predictions to show why Marshall mattered beyond ice cream. The Table teaches aspiration and social mobility while also imagining cold storage, lorries, and future food systems', 'Use servant problem, worker advocacy, women''s work, manners instruction, and technology predictions to show why Marshall mattered beyond ice cream. The Table teaches aspiration and social mobility while also imagining cold storage, lorries, and future food systems. This can also seed Ch. 17, where Marshall becomes future-facing rather than merely Victorian.', 'Ch. 5; references', 'Evidence for advocacy, feminism, and predictions', 70, 'draftable', 'Audit: workable; ~70% present. Needs quote selection'),
  ('B47', 'part-iv-resolution-and-future', 'ch-16', 'Return to Ellen Clarke; Lambeth / Luigi Feretti if verified', 47, '4', 'Return to Ellen Clarke to close the poisoned-pleasure loop. The scene should feel different now because the reader understands vendors, glasses, milk, slums, migration, and public health', 'Return to Ellen Clarke to close the poisoned-pleasure loop. The scene should feel different now because the reader understands vendors, glasses, milk, slums, migration, and public health. If Lambeth / Luigi Feretti is verified, use it carefully; otherwise center the confirmed Clarke material and its consequences.', 'Introduction; Ch. 7', 'Newspaper verification; Feretti details', 60, 'draftable', 'Audit: workable; ~60% present. Strong return'),
  ('B48', 'part-iv-resolution-and-future', 'ch-16', '"Poison! Poison!" crowds and anti-Italian backlash', 48, '4', 'Use “Poison! Poison!” and anti-Italian backlash only if the sources support the crowd scene. The deeper point is that public health panic easily becomes xenophobic blame: a real sanitary problem is projected onto immigrant bodies, accents, shops, and street presence', 'Use “Poison! Poison!” and anti-Italian backlash only if the sources support the crowd scene. The deeper point is that public health panic easily becomes xenophobic blame: a real sanitary problem is projected onto immigrant bodies, accents, shops, and street presence. This block should distinguish danger from scapegoating.', 'Ch. 7', 'Primary-source accounts; careful distinction between disease and scapegoating. Audit adds: Primary-source verification for the crowd scene; distinguish real sanitary danger from scapegoating and xenophobia.', 45, 'research', 'Audit: research-dependent; ~45% present. Needs source work Four pages depend on primary evidence for crowd scene; otherwise merge/shrink.'),
  ('B49', 'part-iv-resolution-and-future', 'ch-16', 'BMJ petition, Glasgow regulation, Public Health Acts, Pure Ice Syndicate, LCC Act 1902, Blake, Levine', 49, '7', 'Make regulation a narrative sequence rather than institutional inventory: Glasgow acts in 1893; BMJ petitions; existing Public Health Acts prove inadequate; Pure Ice Syndicate tries market reform and fails; the LCC Act 1902 creates enforceable rules; Levine''s prosecution shows the law entering domestic production space; Manchester provides contrast. This is the main resolution of the poison arc.', 'Make regulation a narrative sequence rather than institutional inventory: Glasgow acts in 1893; BMJ petitions; existing Public Health Acts prove inadequate; Pure Ice Syndicate tries market reform and fails; the LCC Act 1902 creates enforceable rules; Levine''s prosecution shows the law entering domestic production space; Manchester provides contrast. This is the main resolution of the poison arc.', 'Ch. 8 "Sherbet Strife"', 'Enforcement scenes; prosecution detail', 90, 'draftable', 'Audit: strong existing base; ~90% present. Main resolution'),
  ('B50', 'part-iv-resolution-and-future', 'ch-17', 'Mechanical refrigeration, artificial ice, London ice factories', 50, '5', 'Explain artificial cold as the condition for modern ice cream. Mechanical refrigeration, manufactured ice, London factories, cleaner supply, and scale move ice cream away from natural ice and slum manufacture', 'Explain artificial cold as the condition for modern ice cream. Mechanical refrigeration, manufactured ice, London factories, cleaner supply, and scale move ice cream away from natural ice and slum manufacture. The current thesis is thin here, so this block needs new research unless the chapter is compressed.', 'Ch. 3; old notes', 'Refrigeration timeline; London factory data. Audit adds: Research refrigeration timeline, artificial-ice technology, London factories, cleaner supply, and scale.', 25, 'research', 'Audit: research-dependent; ~25% present. Needs research Research pass required for full 5 pp.'),
  ('B51', 'part-iv-resolution-and-future', 'ch-17', 'Decline of natural ice, domestic refrigerators, cold-chain retail', 51, '5', 'Narrate the decline of natural ice and rise of modern cold chains: fewer imports, more manufactured ice, domestic refrigeration later, retail distribution, and all-class access. This should answer how ice cream becomes ordinary', 'Narrate the decline of natural ice and rise of modern cold chains: fewer imports, more manufactured ice, domestic refrigeration later, retail distribution, and all-class access. This should answer how ice cream becomes ordinary. Verify the 1921 last-import claim, factory counts, and timeline before drafting.', 'Ch. 3; old notes', 'Verify 1921 last imports and factory counts. Audit adds: Verify 1921 last-import claim, factory counts, domestic refrigerator timeline, retail cold-chain development, and all-class access.', 20, 'research', 'Audit: research-dependent; ~20% present. Needs research Research pass required for full 5 pp.'),
  ('B52', 'part-iv-resolution-and-future', 'ch-17', 'Marshall''s liquid nitrogen idea; edible cone precursor', 52, '5', 'Use Marshall''s liquid-nitrogen idea, edible cone precursor, The Table''s cold-storage futurism, and other technology predictions as payoff. The argument is that Marshall did not invent modern ice cream, but she anticipated its direction: branded, technical, theatrical, transportable, and available through systems rather than one household kitchen.', 'Use Marshall''s liquid-nitrogen idea, edible cone precursor, The Table''s cold-storage futurism, and other technology predictions as payoff. The argument is that Marshall did not invent modern ice cream, but she anticipated its direction: branded, technical, theatrical, transportable, and available through systems rather than one household kitchen.', 'Ch. 5; old notes', 'Verify cone and liquid-nitrogen claims. Audit adds: Verify Marshall liquid-nitrogen idea, edible cone precursor, and The Table''s technology predictions; connect to modernity without overstating invention.', 35, 'research', 'Audit: research-dependent; ~35% present. Payoff block Verify liquid nitrogen/cone claims before treating as payoff.'),
  ('B53', 'epilogue', 'epilogue', 'London Canal Museum and Gatti''s ice wells', 53, '2-3', 'Open the epilogue in the London Canal Museum / Gatti ice wells as a physical remnant. This gives the ending a place: under the city, cold infrastructure remains after the vendors, scandals, and celebrity demonstrations have disappeared', 'Open the epilogue in the London Canal Museum / Gatti ice wells as a physical remnant. This gives the ending a place: under the city, cold infrastructure remains after the vendors, scandals, and celebrity demonstrations have disappeared. It should be present-tense, sensory, and short.', 'Ch. 4; acknowledgements', 'Present-day scene and description. Audit adds: Present-day London Canal Museum scene, physical description of ice wells, and sensory descent/space writing.', 35, 'research', 'Audit: research-dependent; ~35% present. Place-based ending'),
  ('B54', 'epilogue', 'epilogue', 'Why luxury mattered to each group', 54, '2-3', 'Replace the descent-only block with the central thesis question in epilogue form: why did luxury matter to each group? For working-class consumers, hokey-pokey could mean pleasure, relief, and a tiny claim on abundance; for elite and aspirational consumers, fancy ices meant status, taste, labor control, and command over technology. Anchor the reflection in the ice wells so the epilogue still ends with place, but let this block articulate the book''s central synthesis.', 'Replace the descent-only block with the central thesis question in epilogue form: why did luxury matter to each group? For working-class consumers, hokey-pokey could mean pleasure, relief, and a tiny claim on abundance; for elite and aspirational consumers, fancy ices meant status, taste, labor control, and command over technology. Anchor the reflection in the ice wells so the epilogue still ends with place, but let this block articulate the book''s central synthesis.', 'Ch. 4', 'Final synthesis of working-class pleasure versus elite/aspirational luxury; keep place-based anchor', 80, 'draftable', 'Audit: workable; ~80% present. Recast per user note'),
  ('B55', 'epilogue', 'epilogue', 'What remains of Gatti and Marshall', 55, '1-2', 'Close with what remains of Gatti and Marshall: luxury made ordinary by infrastructure, labor, regulation, technology, branding, and memory. Keep this to reflection anchored in the ice wells, not a second conclusion', 'Close with what remains of Gatti and Marshall: luxury made ordinary by infrastructure, labor, regulation, technology, branding, and memory. Keep this to reflection anchored in the ice wells, not a second conclusion. The final sentence should return to ice cream as something ordinary only because extraordinary systems made it possible.', 'Full book', 'Final synthesis: luxury, labor, illness, technology, memory', 80, 'draftable', 'Audit: workable; ~80% present. Closing reflection')
